+export default {
+  data() {
+    return {
+      erweimashow: false,
+      isshow: false,
+      uid: '',
+      detail: '',
+      info: '',
+      jzTime: '',
+      done: '',
+      nowTime: '',
+      nick: '',
+      step: 1,
+      infos: {
+        nickname: '',
+        avatarUrl: '',
