+  onLoad(option) {
+    if (option.scancode_time) {
+      const parsedValue = decodeURIComponent(option.q);
+      const queryString = parsedValue.split('?')[1]; // 得到 'name=john&age=30'
+      this.jsonObj = queryString.split('&').reduce((acc, param) => {
+        const [key, value] = param.split('=');
+        acc[key] = value;
+        return acc;
+      }, {});
+      this.uid = this.jsonObj.uid;
+    } else {
+      this.uid = option.uid;
+    }
+    this.info = uni.getStorageSync('detail');
+    this.nick = uni.getStorageSync('infos');
+  },
+  onShow() {
+    this.getDetail();
+    Date.parse(new Date()); // 166796058500
+    this.nowTime = Date.parse(new Date()); // 1667966400000
+    if (uni.getStorageSync('infos') === '') {
+      this.infos = {
+        nickname: '',
+        avatarUrl: '',
+      };
+    } else {
+      this.infos = uni.getStorageSync('infos');
+    }
+  },
+  methods: {
+    goToAvatar() {
+      this.step = 2;
+    },
+    onChooseAvatar(e) {
+      this.infos.avatarUrl = e.detail.avatarUrl;
+      uni.setStorageSync('infos', this.infos);
+    },
+    bindblur(e) {
+      this.infos.nickname = e.detail.value;
+      uni.setStorageSync('infos', this.infos);
+    },
+    complete() {
+      this.show = false;
+      uni.navigateTo({
+        url: `/subpkg/mtHd/detail?uid=${this.uid}`,
+      });
+    },
+    //点击报名参加活动
+    async join() {
+      //   if (!this.nick.nickname || !this.nick.avatarUrl) {
+      //     this.show = true;
+      //   } else {
+      uni.navigateTo({
+        url: `/subpkg/community/detail?uid=${this.uid}`,
+      });
+      //   }
+    },
+    useJoin() {
+      uni.$common.showMsg('已报名');
+    },
+    async getDetail() {
+      const res = await activityDetail({ uid: this.uid });
+      if (res.data) {
+        this.detail = res.data;
+        const backendTime = this.detail.start_time;
+        // 使用 dayjs 解析后端时间并创建 dayjs 对象
+        const backendDayjs = dayjs(backendTime, 'YYYY-MM-DD HH:mm:ss');
+        // 获取当前时间
+        const currentDayjs = dayjs();
+        // 计算后端时间加上 30 分钟后的时间
+        const deadlineDayjs = backendDayjs.subtract(2, 'hour');
+        // 判断当前时间是否超过 30 分钟
+        if (currentDayjs.isBefore(deadlineDayjs)) {
+          this.done = true; // 可以报名
+        } else {
+          this.done = false; // 超过报名时间
+        }
+        this.detail.date = this.detail.start_time.slice(5, 10);
+        this.detail.time = this.detail.start_time.slice(11);
+        this.jzTime = this.addBefore2Hours(this.detail, 'start_time');
+        this.detail.start_formatted = this.formatDateTime(
+          this.detail.start_time
+        );
+        this.detail.end_formatted = this.formatDateTime(this.detail.end_time);
+        this.detail.duration_hours = this.getDurationInHours(
+          this.detail.start_time,
+          this.detail.end_time
+        );
+      } else {
+        this.detail = {};
+      }
+    },
+    formatDateTime(datetimeStr) {
+      if (!datetimeStr) return '';
+      const date = new Date(datetimeStr.replace(/-/g, '/'));
+      const M = String(date.getMonth() + 1).padStart(2, '0');
+      const D = String(date.getDate()).padStart(2, '0');
+      const h = String(date.getHours()).padStart(2, '0');
+      const m = String(date.getMinutes()).padStart(2, '0');
+      const s = String(date.getSeconds()).padStart(2, '0');
+
+      return `${M}-${D} ${h}:${m}:${s}`;
+    },
+    getDurationInHours(startStr, endStr) {
+      const start = new Date(startStr.replace(/-/g, '/'));
+      const end = new Date(endStr.replace(/-/g, '/'));
+      const diffMs = end - start;
+      const diffHours = diffMs / (1000 * 60 * 60); // 毫秒转小时
+      return Math.round(diffHours * 10) / 10; // 保留1位小数
+    },
+    addBefore2Hours(obj, field = 'end_time') {
+      const original = obj[field];
+      if (!original) return obj;
+      const date = new Date(original.replace(/-/g, '/')); // 兼容 Safari
+      date.setMinutes(date.getMinutes() - 120); // 减去 2 小时
+      const Y = date.getFullYear();
+      const M = String(date.getMonth() + 1).padStart(2, '0');
+      const D = String(date.getDate()).padStart(2, '0');
+      const h = String(date.getHours()).padStart(2, '0');
+      const m = String(date.getMinutes()).padStart(2, '0');
+      const s = String(date.getSeconds()).padStart(2, '0');
+      // 返回完整的年月日时间
+      obj.before_2h_time = {
+        full: `${Y}-${M}-${D} ${h}:${m}:${s}`, // 带年月日时间
+        date: `${M}-${D}`, // 只要月-日
+        time: `${h}:${m}:${s}`, // 时间部分
+      };
+
+      return obj;
+    },
+    //点击前往地址
+    goAddress() {
+      console.log(1);
+      var that = this;
+      uni.openLocation({
